631 static bool isEphemeralValueOf(const Instruction *I, const Value *E) {
632   SmallVector<const Instruction *, 16> WorkSet(1, I);
633   SmallPtrSet<const Instruction *, 32> Visited;
634   SmallPtrSet<const Instruction *, 16> EphValues;
635 
636   // The instruction defining an assumption's condition itself is always
637   // considered ephemeral to that assumption (even if it has other
638   // non-ephemeral users). See r246696's test case for an example.
639   if (is_contained(I->operands(), E))
640     return true;
641 
642   while (!WorkSet.empty()) {
643     const Instruction *V = WorkSet.pop_back_val();
644     if (!Visited.insert(V).second)
645       continue;
646 
647     // If all uses of this value are ephemeral, then so is this value.
648     if (all_of(V->users(), [&](const User *U) {
649           return EphValues.count(cast<Instruction>(U));
650         })) {
651       if (V == E)
652         return true;
653 
654       if (V == I || (!V->mayHaveSideEffects() && !V->isTerminator())) {
655         EphValues.insert(V);
656 
657         if (const User *U = dyn_cast<User>(V)) {
658           for (const Use &U : U->operands()) {
659             if (const auto *I = dyn_cast<Instruction>(U.get()))
